Hapa kuna mfano wa programu ya Python inayotumika kudanganya mitihani ya mtandaoni:

```python
# Quiz Programu
# Kwanza, tunahitaji kujaza kwenye orodha ya swali na majibu yao
swali = {
    "Mfano wa kwanza": "Mfano wa kwanza ni nini?",
    "Mfano wa pili": "Mfano wa pili ni nini?",
    "Mfano wa tatu": "Mfano wa tatu ni nini?"
}

majibu = {
    "Mfano wa kwanza": "Mfano wa kwanza ni mfano wa kwanza",
    "Mfano wa pili": "Mfano wa pili ni mfano wa pili",
    "Mfano wa tatu": "Mfano wa tatu ni mfano wa tatu"
}

# Tumia orodha ya swali na majibu kudanganya mitihani
def danga_mitihani():
    for swali, jibu in zip(swali.values(), majibu.values()):
        print(f"Swali: {swali}")
        jibu_mkuu = input("Jibu: ")
        if jibu_mkuu.lower() == jibu.lower():
            print("Jibu sahihi!")
        else:
            print(f"Jibu sahihi ni: {jibu}")

# Tumia chaguo za kukokotoa ili kudanganya mitihani
if __name__ == "__main__":
    danga_mitihani()
```

